import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Quote — base premiums and edge cases
  it.todo("empty item list yields premium of 5 G (processing fee only)");
  it.todo("single sword with no modifiers yields 100 G + 5 G fee = 105 G");
  it.todo("single amulet base premium 60 G + fee = 65 G");
  it.todo("single staff base premium 80 G + fee = 85 G");
  it.todo("single potion base premium 40 G + fee = 45 G");
  it.todo("two swords sum to 200 G + fee = 205 G");

  // Components and blocks
  it.todo("single component (rune) base premium 25 G + fee = 30 G");
  it.todo("2 runes → 50 G base + fee = 55 G");
  it.todo("3 alike runes → 60 G block discount + fee = 65 G");
  it.todo("4 runes → 100 G (no block) + fee = 105 G");
  it.todo("7 runes → 175 G base premium + fee = 180 G");
  it.todo("2 runes + 1 moonstone → 75 G + fee = 80 G (different types, no block)");
  it.todo("3 runes + 3 moonstones → 120 G + fee = 125 G (two separate blocks)");

  // Item-specific modifiers
  it.todo("cursed sword adds 50% surcharge on item base (100 + 50) + fee = 155 G");
  it.todo("sword with enchantment exactly 5 adds 30% high-enchantment surcharge");
  it.todo("sword with enchantment 4 has no high-enchantment surcharge");
  it.todo("cursed sword with enchantment 5 applies both surcharges");

  // Policy-wide modifiers
  it.todo("customer with exactly 2 years gets 20% loyalty discount");
  it.todo("first insurance adds 10% on policy base premium");
  it.todo("second contract gets 15% follow-up discount");
  it.todo("modifier scope: cursed sword + plain amulet → policy base 160 G, +50 G cursed, +fee");

  // Rounding
  it.todo("premium calculation rounds up in MHPCO's favor");

  // Integration examples from spec
  it.todo("newcomer with cursed sword → 165 G");
  it.todo("long-standing customer's second contract with cursed enchanted sword → 160 G");

  // Claims — basic
  it.todo("standard sword damage 500 G → payout 400 G (full minus 100 G deductible)");
  it.todo("rune damage 200 G → payout 100 G");
  it.todo("damage to item with enchantment >=8 reimbursed at 50%");
  it.todo("damage to dragon material item fully reimbursed");
  it.todo("dragon material sword enchantment 9 damage 1000 → payout 400 (50% wins)");
  it.todo("dragon material sword enchantment 5 damage 800 → payout 700");
  it.todo("steel sword enchantment 9 damage 1000 → payout 400");
  it.todo("multiple damages each get own deductible");
  it.todo("policy cap = 2× insurance sum, exhaustion across multiple claims");
  it.todo("payout rounds down in MHPCO's favor");

  // Validation / error handling
  it.todo("unknown item type in quote → non-zero exit, error to stderr");
  it.todo("claim referencing item not in policy → non-zero exit");
  it.todo("claim with negative damage amount → non-zero exit");
  it.todo("more damage entries of a type than policy covers → non-zero exit");
});

