const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

const RUNE_BLOCK_SIZE = 3;
const RUNE_BLOCK_PRICE = 60;

const itemBasePremium = (item: any): number => BASE_PREMIUMS[item.type];

const sumItemPremiums = (items: any[]): number =>
  items.reduce((sum, item) => sum + itemBasePremium(item), 0);

const calculateBasePremium = (items: any[]): number => {
  const runes = items.filter((item) => item.type === "rune");
  const others = items.filter((item) => item.type !== "rune");
  if (runes.length === RUNE_BLOCK_SIZE) {
    return RUNE_BLOCK_PRICE + sumItemPremiums(others);
  }
  return sumItemPremiums(items);
};

const addPercent = (amount: number, percent: number): number =>
  amount + (amount * percent) / 100;

const quotePremium = (items: any[]): number => {
  const base = calculateBasePremium(items);
  const withSurcharge = addPercent(base, FIRST_INSURANCE_SURCHARGE_PERCENT);
  return Math.ceil(withSurcharge + PROCESSING_FEE);
};

export const runScenario = (scenario: any): unknown => {
  const items = scenario.steps[0].items;
  return { results: [{ premium: quotePremium(items) }] };
};

