    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "dragon", enchantment: 9, cursed: false }],
        },
        {
          op: "claim",
          policy: 0,
          incident: {
            cause: "dragon",
            damages: [{ itemType: "sword", amount: 1000 }],
          },
        },
      ],
    });
    expect(result).toEqual({
      results: [{ premium: 145 }, { payout: 400, remainingCap: 1600 }],
    });
  });
  it.todo("dragon material sword enchantment 9 damage 1000 → payout 400 (50% wins)");
  it.todo("dragon material sword enchantment 5 damage 800 → payout 700");
  it.todo("steel sword enchantment 9 damage 1000 → payout 400");
  it.todo("multiple damages each get own deductible");
  it("cap exhaustion across multiple claims on same policy", () => {
    // sword insurance value 1000, cap 2000
    // first claim 1500 → payout 1400, cap remaining 600
    // second claim 1500 → desired 1400 but capped at 600 → payout 600, remaining 0
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }],
        },
        {
          op: "claim",
          policy: 0,
          incident: { cause: "fire", damages: [{ itemType: "sword", amount: 1500 }] },
        },
        {
